        className="absolute inset-[-10%] opacity-50 transition-transform duration-1000 ease-out"
        style={{ transform: `translate3d(${mousePos.x * -0.01}px, ${mousePos.y * -0.01}px, 0)` }}
      >
        {[...Array(150)].map((_, i) => (
          <div 
            key={i}
            className="absolute rounded-full bg-white animate-pulse"
            style={{
              width: Math.random() * 1.5 + 'px',
