            style={{
              top: Math.random() * 100 + '%',
              left: '-50%',
              animationDelay: (Math.random() * 12) + 's',
              transform: `rotate(${(Math.random() * 6) - 3}deg)`
            }}
          />
        ))}
      </div>

      {/* Fiery Solar Flares / Nebulae */}
      <div 
