                  ? 'flex-[8] bg-orange-500/[0.08] border-orange-500/60 shadow-[0_20px_60px_-15px_rgba(234,88,12,0.3)] -translate-y-3' 
                  : isAnyHovered 
                    ? 'flex-[1] opacity-20 blur-[2px] border-white/5 bg-white/[0.01] translate-y-2' 
                    : 'flex-[2] border-white/20 bg-white/[0.04] shadow-lg translate-y-0'
