                 <span className={`text-[10px] font-black font-mono tracking-[0.2em] vertical-text transition-colors ${!isAnyHovered ? 'text-white/50' : 'text-white/20'}`}>MODULE_0{idx + 1}</span>
                 <div className={`w-[1px] h-10 transition-all ${!isAnyHovered ? 'bg-white/30 h-12' : 'bg-white/10'}`}></div>
              </div>

              {/* Expanded Content Reveal */}
              <div className={`flex flex-col h-full w-full p-6 md:p-10 transition-all duration-500 ${isHovered ? 'opacity-100 scale-100 translate-y-0' : 'opacity-0 scale-95 translate-y-6 absolute inset-0'}`}>
                <div className="flex items-center gap-4 mb-4">
                   <div className="w-12 h-12 rounded-[1rem] glass border border-orange-500/30 flex items-center justify-center bg-orange-500/20 shadow-[0_0_20px_rgba(234,88,12,0.2)] transition-transform duration-500 hover:scale-110">
                      <span className="text-xl font-black text-orange-500">0{idx + 1}</span>
                   </div>
                   <div className="flex flex-col">
                      <span className="text-[8px] font-black text-orange-500 tracking-[0.4em] uppercase leading-none">SYSTEM_LIFT_ACTIVE</span>
                      <div className="flex items-center gap-1.5 mt-1.5">
                        <div className="w-1.5 h-1.5 rounded-full bg-orange-400 animate-ping"></div>
                        <span className="text-[7px] font-bold text-white/50 uppercase tracking-widest">Optimizing</span>
                      </div>
