const ProjectDetailView: React.FC<{ 
  project: Project; 
  projects: Project[];
  onBack: () => void; 
  onNext: () => void 
}> = ({ project, projects, onBack, onNext }) => {
  const [activeSection, setActiveSection] = useState('hero');
  const [activeProcessIdx, setActiveProcessIdx] = useState(0);

  const sections = [
    { id: 'hero', label: 'Intro' },
    { id: 'overview', label: 'Overview' },
    { id: 'problem', label: 'Problem' },
    { id: 'research', label: 'Research' },
    { id: 'solution', label: 'Solution' },
    { id: 'process', label: 'Process' },
    { id: 'design', label: 'Design' },
    { id: 'impact', label: 'Impact' },
  ];

  useEffect(() => {
    const handleScroll = () => {
      const buffer = 150;
      let currentSectionId = sections[0].id;
      for (const section of sections) {
        const element = document.getElementById(section.id);
        if (element) {
          const rect = element.getBoundingClientRect();
          if (rect.top <= buffer) currentSectionId = section.id;
        }
      }
      setActiveSection(currentSectionId);
    };
    window.addEventListener("scroll", handleScroll, { passive: true });
    return () => window.removeEventListener("scroll", handleScroll);
  }, [sections]);

  const scrollToSection = (id: string) => {
    document.getElementById(id)?.scrollIntoView({ behavior: 'smooth', block: 'start' });
  };

  const currentProcessStep = project.processSteps?.[activeProcessIdx] || { title: 'Process', subtitle: '', imageUrl: '', ideationText: '' };
  const nextProject = projects[(projects.findIndex(p => p.id === project.id) + 1) % PROJECTS.length];
  const showNav = ['problem', 'research', 'solution', 'process', 'design', 'impact'].includes(activeSection);

  const insights = [
    { text: project.researchInsights, icon: (
      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 20l-5.447-2.724A2 2 0 013 15.487V6a2 2 0 011.137-1.81l5.447-2.724a2 2 0 011.83 0L15 4.147m-6 15.853V4.147m6 15.853l5.447-2.724A2 2 0 0021 15.487V6a2 2 0 00-1.137-1.81l-5.447-2.724a2 2 0 00-1.83 0L9 4.147m6 0V19.853" />
      </svg>
    )},
    { text: project.researchInsight2, icon: (
      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M13.828 10.172a4 4 0 00-5.656 0l-4 4a4 4 0 105.656 5.656l1.102-1.101m-.758-4.899a4 4 0 005.656 0l4-4a4 4 0 105.656 5.656l1.1 1.1" />
      </svg>
    )},
    { text: project.researchInsight3, icon: (
      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
      </svg>
    )}
  ].filter(i => i.text);

  return (
    <div className="bg-transparent min-h-screen relative z-10">
      <div className={`fixed right-0 top-0 bottom-0 w-16 z-[100] hidden lg:flex flex-col items-center justify-center transition-all duration-700 ${showNav ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}>
        <nav className="flex flex-col gap-6 items-center">
          {sections.map((section) => (
            <button key={section.id} onClick={() => scrollToSection(section.id)} className="group relative flex items-center justify-center w-full h-8">
              <div className={`absolute right-10 px-3 py-1.5 glass rounded-full border border-white/5 transition-all duration-300 opacity-0 group-hover:opacity-100 ${activeSection === section.id ? 'opacity-100 border-orange-500/20' : ''}`}>
