import React, { useEffect, useState } from 'react';

interface LoadingScreenProps {
  onLoadingComplete: () => void;
}

const LoadingScreen: React.FC<LoadingScreenProps> = ({ onLoadingComplete }) => {
  const [progress, setProgress] = useState(0);
  const [isExiting, setIsExiting] = useState(false);

  useEffect(() => {
    const interval = setInterval(() => {
      setProgress((prev) => {
        if (prev >= 100) {
          clearInterval(interval);
          setTimeout(() => setIsExiting(true), 500);
          setTimeout(onLoadingComplete, 1300); // Wait for exit animation
          return 100;
        }
        // Random increments for a more organic feel
        const increment = Math.floor(Math.random() * 15) + 5;
        return Math.min(prev + increment, 100);
      });
    }, 150);

    return () => clearInterval(interval);
  }, [onLoadingComplete]);

  return (
    <div 
      className={`fixed inset-0 z-[9999] bg-black flex flex-col items-center justify-center transition-all duration-1000 ease-in-out ${
        isExiting ? 'opacity-0 scale-110 pointer-events-none' : 'opacity-100 scale-100'
      }`}
    >
      {/* Background Glow */}
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[600px] h-[600px] bg-white/5 rounded-full blur-[120px] pointer-events-none"></div>

      <div className="relative flex flex-col items-center gap-8">
        {/* Logo Section */}
        <div className="flex flex-col items-center">
          <div className="text-2xl md:text-3xl font-bold tracking-tighter mb-2">
            J<span className="text-white/30 italic font-medium">T</span>
          </div>
          <div className="h-[1px] w-12 bg-white/10 overflow-hidden relative">
            <div 
              className="absolute inset-0 bg-white/40 transition-all duration-300 ease-out" 
              style={{ width: `${progress}%` }}
            ></div>
          </div>
        </div>

        {/* Counter Section */}
        <div className="flex flex-col items-center">
          <span className="text-4xl md:text-6xl font-black font-mono tracking-tighter tabular-nums text-white">
            {progress.toString().padStart(2, '0')}<span className="text-white/20 text-xl">%</span>
          </span>
          <span className="text-[10px] font-bold tracking-[0.5em] uppercase text-white/30 mt-4">
            Optimizing Interface
          </span>
        </div>
      </div>

      {/* Decorative corners */}
      <div className="absolute top-12 left-12 w-8 h-8 border-t border-l border-white/10"></div>
      <div className="absolute top-12 right-12 w-8 h-8 border-t border-r border-white/10"></div>
      <div className="absolute bottom-12 left-12 w-8 h-8 border-b border-l border-white/10"></div>
      <div className="absolute bottom-12 right-12 w-8 h-8 border-b border-r border-white/10"></div>
    </div>
  );
};

