// Interactive North Star Component
const NorthStarCard: React.FC<{ label: string; description: string }> = ({ label, description }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const [isHovered, setIsHovered] = useState(false);

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    setMousePos({ x, y });
  };

  return (
    <div 
      ref={containerRef}
      onMouseMove={handleMouseMove}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      className="group relative w-full glass p-10 md:p-14 rounded-[3rem] border-white/20 transition-all duration-700 hover:border-orange-500/30 shadow-2xl overflow-hidden cursor-default perspective-1000"
      style={{
        transform: isHovered 
          ? `perspective(1000px) rotateX(${(mousePos.y / 200 - 1) * -2}deg) rotateY(${(mousePos.x / 400 - 1) * 2}deg)` 
          : 'none'
      }}
    >
      {/* Dynamic Light Tracking */}
      <div 
        className="absolute pointer-events-none transition-opacity duration-500 rounded-full blur-[100px]"
        style={{
          opacity: isHovered ? 0.15 : 0,
          background: 'radial-gradient(circle, rgba(234,88,12,0.4) 0%, transparent 70%)',
          width: '400px',
          height: '400px',
          left: `${mousePos.x - 200}px`,
          top: `${mousePos.y - 200}px`,
        }}
      />

      {/* Shimmer Animation */}
      <div className="absolute inset-0 pointer-events-none overflow-hidden">
        <div className="absolute -inset-x-full top-0 h-full w-[200%] bg-gradient-to-r from-transparent via-white/[0.03] to-transparent -skew-x-12 animate-shimmer" />
      </div>

