        <div className="w-10 h-[1.5px] bg-gradient-to-r from-transparent via-white/20 to-transparent mb-6" />

        <p className="text-base md:text-lg text-white/40 font-light italic leading-relaxed group-hover:text-white/70 transition-all duration-[600ms]">
