          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0012 18.75c-1.03 0-1.9-.4-2.593-.579a5.356 5.356 0 01-.84-.371z" />
        </svg>
      )
    }
  ];

  const handleStepChange = (idx: number) => {
    if (idx === activeStep) return;
    setIsRotating(true);
    setActiveStep(idx);
    setTimeout(() => setIsRotating(false), 600);
  };

  return (
    <div className="w-full max-w-5xl mx-auto mt-16 relative flex flex-col lg:flex-row items-center justify-center gap-12 lg:gap-16 px-6 reveal">

