             {[...Array(3)].map((_, i) => (
               <div key={i} className={`w-1.5 h-1.5 rounded-full ${i === activeStep ? 'bg-orange-500 scale-125 shadow-[0_0_8px_rgba(234,88,12,1)]' : 'bg-white/20'} transition-all duration-500`}></div>
             ))}
           </div>
        </div>

        <div className="absolute inset-0 rounded-full border border-white/10 shadow-[inset_0_0_20px_rgba(255,255,255,0.01)]"></div>
