        {steps.map((step, idx) => {
          const angle = (idx * (360 / steps.length)) - 90;
          const isActive = activeStep === idx;
          const rotationAngle = angle + (activeStep * -120);

          return (
            <div 
              key={step.id}
              className="absolute top-1/2 left-1/2 w-full h-full transition-transform duration-700 ease-[cubic-bezier(0.2,1,0.3,1)] z-30 pointer-events-none"
              style={{ transform: `translate3d(-50%, -50%, 0) rotate(${rotationAngle}deg)` }}
            >
              <button 
                onClick={() => handleStepChange(idx)}
                className={`absolute top-0 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-auto transition-all duration-500 ${
                  isActive ? 'scale-110' : 'scale-90 opacity-60 hover:opacity-100 hover:scale-100'
                }`}
              >
                <div 
                  className="flex flex-col items-center gap-2 transition-transform duration-700"
                  style={{ transform: `rotate(${-rotationAngle}deg)` }}
                >
                  <div className={`w-14 h-14 md:w-16 md:h-16 glass rounded-2xl border-2 flex items-center justify-center relative overflow-hidden transition-all duration-500 bg-black/60 shadow-xl ${
                    isActive ? 'border-orange-500 shadow-[0_0_25px_rgba(234,88,12,0.3)]' : 'border-white/20 hover:border-white/40'
                  }`}>
                    <div className={`${isActive ? 'text-orange-500' : 'text-white/60'} transition-colors duration-500`}>
                      {step.icon}
                    </div>
                  </div>
                  <span className={`text-[8px] font-bold tracking-widest uppercase transition-colors duration-500 ${isActive ? 'text-orange-500' : 'text-white/40'}`}>
                    {step.phase}
                  </span>
                </div>
              </button>
            </div>
          );
        })}
      </div>

      <div className="flex-1 w-full max-md:hidden relative">
        <div 
          className={`glass p-8 md:p-10 rounded-[2.5rem] border border-white/10 relative overflow-hidden transition-all duration-500 shadow-2xl min-h-[320px] flex flex-col justify-center bg-white/[0.01] ${
            isRotating ? 'opacity-0 translate-x-4 blur-md' : 'opacity-100 translate-x-0 blur-none'
          }`}
        >
          <div className="absolute top-0 left-0 w-full h-[1.5px] bg-gradient-to-r from-transparent via-orange-500/20 to-transparent"></div>

          <div className="relative z-10">
            <div className="flex items-center gap-3 mb-6">
              <span className="text-[10px] font-bold tracking-[0.2em] text-orange-500/60 uppercase">
                {steps[activeStep].label}
              </span>
              <div className="h-[1px] flex-1 bg-white/5"></div>
            </div>

            <h3 className="text-2xl md:text-3xl font-bold tracking-tight text-white mb-6 leading-none uppercase">
