// Refined Interactive North Star Component
const NorthStarCard: React.FC<{ label: string; description: string }> = ({ label, description }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const [isHovered, setIsHovered] = useState(false);

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    setMousePos({ x, y });
  };

  return (
    <div 
      ref={containerRef}
      onMouseMove={handleMouseMove}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      className="group relative w-full max-w-2xl mx-auto glass p-8 md:p-10 rounded-[2.5rem] border border-white/20 transition-all duration-[800ms] hover:border-orange-500/40 shadow-2xl overflow-hidden cursor-default perspective-1000 bg-white/[0.01]"
      style={{
        transform: isHovered 
          ? `perspective(1000px) rotateX(${(mousePos.y / 200 - 1) * -1.5}deg) rotateY(${(mousePos.x / 300 - 1) * 1.5}deg)` 
          : 'none'
      }}
    >
      <div className="absolute inset-0 opacity-[0.03] pointer-events-none bg-[url('https://grainy-gradients.vercel.app/noise.svg')] brightness-100 contrast-150 mix-blend-overlay"></div>

      <div 
        className="absolute pointer-events-none transition-all duration-700 rounded-full blur-[80px] z-0"
        style={{
          opacity: isHovered ? 0.2 : 0,
          background: 'radial-gradient(circle, rgba(255,255,255,0.8) 0%, rgba(234,88,12,0.4) 30%, transparent 70%)',
          width: '300px',
          height: '300px',
          left: `${mousePos.x - 150}px`,
          top: `${mousePos.y - 150}px`,
          transform: `translate3d(${(mousePos.x - 150) * 0.05}px, ${(mousePos.y - 150) * 0.05}px, 0)`
        }}
      />

      <div className="absolute inset-0 pointer-events-none overflow-hidden">
        <div className="absolute -inset-x-full top-0 h-full w-[200%] bg-gradient-to-r from-transparent via-orange-500/[0.05] to-transparent -skew-x-12 animate-refraction-sweep" />
      </div>

      <div className="relative z-10 flex flex-col items-center text-center max-w-xl mx-auto">
        <div className="flex items-center gap-2.5 mb-6 opacity-60 group-hover:opacity-100 transition-opacity duration-700">
