// Refined Interactive North Star Component
const NorthStarCard: React.FC<{ label: string; description: string }> = ({ label, description }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const [isHovered, setIsHovered] = useState(false);

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    setMousePos({ x, y });
  };

  return (
    <div 
      ref={containerRef}
      onMouseMove={handleMouseMove}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      className="group relative w-full max-w-2xl mx-auto glass p-10 md:p-12 rounded-[2rem] border border-white/10 transition-all duration-[1s] hover:border-orange-500/30 shadow-2xl overflow-hidden cursor-default perspective-1000"
      style={{
        transform: isHovered 
          ? `perspective(1000px) rotateX(${(mousePos.y / 200 - 1) * -1}deg) rotateY(${(mousePos.x / 300 - 1) * 1}deg)` 
          : 'none'
      }}
    >
      <div 
        className="absolute pointer-events-none transition-opacity duration-700 rounded-full blur-[100px] z-0"
        style={{
          opacity: isHovered ? 0.15 : 0,
          background: 'radial-gradient(circle, rgba(255,255,255,1) 0%, rgba(234,88,12,0.4) 50%, transparent 100%)',
          width: '400px',
          height: '400px',
          left: `${mousePos.x - 200}px`,
          top: `${mousePos.y - 200}px`
        }}
      />

      <div className="relative z-10 flex flex-col items-center text-center max-w-xl mx-auto">
        <div className="flex items-center gap-3 mb-8 opacity-40 group-hover:opacity-100 transition-opacity duration-700">
           <span className="text-[10px] font-bold text-white tracking-[0.4em] uppercase">Core focus</span>
        </div>

        <h3 className="text-3xl md:text-5xl font-bold text-white mb-6 leading-[0.9] tracking-tight group-hover:text-orange-50 transition-colors">
          {label}
        </h3>

        <p className="text-lg md:text-xl text-white/50 font-light leading-relaxed group-hover:text-white/80 transition-all duration-700">
          "{description}"
        </p>
      </div>

      <div className="absolute bottom-0 left-0 w-full h-[1px] bg-gradient-to-r from-transparent via-orange-500/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-1000"></div>
    </div>
  );
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('work');
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      setMousePos({ x: e.clientX, y: e.clientY });
    };
    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  useEffect(() => {
    const handleScroll = () => {
      const layers = document.querySelectorAll('.parallax-layer');
      layers.forEach((layer) => {
        const element = layer as HTMLElement;
        const rect = element.getBoundingClientRect();
        const viewportHeight = window.innerHeight;

        if (rect.top < viewportHeight && rect.bottom > 0) {
          const customSpeed = parseFloat(element.dataset.speed || '0.08');
          const yPos = (rect.top - viewportHeight / 2) * customSpeed;
          element.style.transform = `translate3d(0, ${yPos}px, 0)`;
        }
      });
    };

    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    const revealObserver = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          entry.target.classList.add('reveal-visible');
        }
      });
    }, { threshold: 0.1 });

    document.querySelectorAll('.reveal').forEach(el => revealObserver.observe(el));
    if (!isLoading) window.scrollTo(0, 0);

    return () => revealObserver.disconnect();
  }, [currentView, isLoading, selectedProject]);

  const handleProjectClick = (project: Project) => {
    setSelectedProject(project);
    setCurrentView('project-detail');
  };

  const renderView = () => {
    const activeProject = selectedProject ? PROJECTS.find(p => p.id === selectedProject.id) : null;

    switch (currentView) {
      case 'case-studies':
        return <CaseStudiesView projects={PROJECTS} onSelectProject={handleProjectClick} />;
      case 'info':
        return <InfoView />;
      case 'project-detail':
        return activeProject ? (
          <ProjectDetailView 
            project={activeProject} 
            projects={PROJECTS}
            onBack={() => setCurrentView('work')} 
            onNext={() => {
              const idx = PROJECTS.findIndex(p => p.id === activeProject.id);
              const next = PROJECTS[(idx + 1) % PROJECTS.length];
              setSelectedProject(next);
              window.scrollTo({ top: 0, behavior: 'smooth' });
            }}
          />
        ) : <WorkView projects={PROJECTS} onProjectClick={handleProjectClick} />;
      default:
        return <WorkView projects={PROJECTS} onProjectClick={handleProjectClick} />;
    }
  };

  return (
    <div className="min-h-screen bg-black custom-cursor-area relative selection:bg-white selection:text-black">
      <CinematicBackground mousePos={mousePos} />
      <CustomCursor />
      {isLoading && <LoadingScreen onLoadingComplete={() => setIsLoading(false)} />}

      <Header currentView={currentView} onViewChange={(view) => {
        setCurrentView(view);
        setSelectedProject(null);
      }} />

      <main className={`relative z-10 transition-opacity duration-1000 ${isLoading ? 'opacity-0' : 'opacity-100'}`}>
        {renderView()}
      </main>

      <footer id="contact" className="relative z-10 py-32 px-6 border-t border-white/5 backdrop-blur-sm">
        <div className="max-w-7xl mx-auto flex flex-col items-center text-center reveal">
          <h2 className="text-5xl md:text-[7vw] font-bold tracking-tight mb-20 leading-[0.9]">
            Let’s build <span className="text-white/30">something new</span>.
          </h2>

          <div className="w-full pt-12 border-t border-white/5 flex flex-col md:flex-row justify-between items-center gap-8 text-white/30 text-[10px] font-bold tracking-[0.4em] uppercase font-sans">
            <div>© 2024 JT Studio</div>
            <div className="flex gap-12">
              <a href="#" className="hover:text-white transition-colors">LinkedIn</a>
              <a href="#" className="hover:text-white transition-colors">Behance</a>
              <a href="#" className="hover:text-white transition-colors">Contact</a>
            </div>
            <div>Berlin, Germany</div>
          </div>
        </div>
      </footer>
    </div>
  );
};

